import { modelSupportsThinking } from '../../utils/thinking.js';
import { logAPISuccessAndDuration, logAPIError } from './logging.js';

export interface ZenithRequestConfig {
  model: string;
  messages: Array<{ role: string; content: string }>;
  systemPrompt?: string;
  temperature?: number;
}

const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 1000;

function isRetryableError(error: Error): boolean {
  const retryableCodes = [
    "ETIMEDOUT", "ECONNRESET", "ENOTFOUND",
    "ECONNREFUSED", "ESOCKETTIMEDOUT", "EPIPE",
    "UND_ERR_SOCKET",
    "network request failed",
    "500 Internal Server Error",
    "502 Bad Gateway",
    "503 Service Unavailable",
    "504 Gateway Timeout",
  ];
  const lowerCaseRetryableCodes = retryableCodes.map(code => code.toLowerCase());

  const checkMessage = (message: string) =>
    lowerCaseRetryableCodes.some(code => message.toLowerCase().includes(code));

  return checkMessage(error.message) ||
         (error.cause instanceof Error && checkMessage(error.cause.message));
}

export async function sendSovereignRequest(config: ZenithRequestConfig): Promise<Response> {
  const startTime = Date.now();
  const isThinkingEnabled = modelSupportsThinking(config.model);
  const endpoint = process.env.ZENITH_API_ENDPOINT || "https://openrouter.ai/api/v1/chat/completions";
  const apiKey = process.env.ZENITH_API_KEY || process.env.AETHER_RELAY_KEY_ALPHA;

  if (!apiKey) {
    throw new Error("AETHER-ZENITH_ERR: No API key configured. Set ZENITH_API_KEY or AETHER_RELAY_KEY_ALPHA.");
  }

  const headers = {
    "Authorization": `Bearer ${apiKey}`,
    "Content-Type": "application/json",
    "X-Title": "AETHER-ZENITH Sovereign Engine V15.0",
    "HTTP-Referer": "https://aether-zenith.ai",
    "Anthropic-Beta": "prompt-caching-2024-07-31"
  };

  const systemPromptMessage = config.systemPrompt ? [{
    role: "system",
    content: config.systemPrompt,
    ...(config.systemPrompt.length > 200 && { cache_control: { type: "ephemeral" } })
  }] : [];

  const body = {
    model: config.model.includes('aether') || config.model.includes('zenith')
           ? "google/gemini-2.5-flash"
           : config.model,
    messages: [
      ...systemPromptMessage,
      ...config.messages
    ],
    temperature: config.temperature ?? 0.2,
    max_tokens: 3000,
    stream: true,
    ...(isThinkingEnabled && {
      thinking: {
        type: "enabled",
        budget_tokens: parseInt(process.env.MAX_THINKING_TOKENS || "2048", 10)
      }
    })
  };

  let lastError: Error | null = null;

  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
    try {
      const response = await fetch(endpoint, {
        method: "POST",
        headers,
        body: JSON.stringify(body)
      });

      if (!response.ok) {
        let errorData: unknown;
        try {
          errorData = await response.json();
        } catch (jsonError) {
          errorData = { message: `HTTP error! status: ${response.status}`, originalError: jsonError };
        }
        const errorMessage = `Sovereign API Error: ${response.status} - ${JSON.stringify(errorData)}`;
        const apiError = new Error(errorMessage);
        apiError.cause = errorData;

        logAPIError({
          error: apiError,
          model: config.model,
          messageCount: config.messages.length,
          durationMs: Date.now() - startTime,
          attempt,
        });

        if (attempt < MAX_RETRIES && isRetryableError(apiError)) {
          lastError = apiError;
          await new Promise(resolve => setTimeout(resolve, RETRY_DELAY_MS * attempt));
          continue;
        }
        throw apiError;
      }

      try {
        // Logging success for streaming requests might need more granular data
        // once the stream is consumed, but for now, log initial success.
        logAPISuccessAndDuration({
          model: config.model,
          preNormalizedModel: config.model,
          start: startTime,
          startIncludingRetries: startTime,
          ttftMs: null, // TTFT is not known at this point for streaming
          usage: {
            input_tokens: 0, // Usage is not known at this point for streaming
            output_tokens: 0,
            cache_creation_input_tokens: 0,
            cache_read_input_tokens: 0,
          },
          attempt,
          messageCount: config.messages.length,
          messageTokens: 0, // Not known at this point
          requestId: null, // Not known at this point
          stopReason: null, // Not known at this point
          didFallBackToNonStreaming: false,
          querySource: "zenith-api-client",
          costUSD: 0, // Not known at this point
        });
      } catch (logErr) {
        console.error("Error logging API success:", logErr);
      }
      return response;
    } catch (error: unknown) {
      lastError = error instanceof Error ? error : new Error(String(error));
      if (attempt < MAX_RETRIES && isRetryableError(lastError)) {
        await new Promise(resolve => setTimeout(resolve, RETRY_DELAY_MS * attempt));
        continue;
      }
      logAPIError({
        error: lastError,
        model: config.model,
        messageCount: config.messages.length,
        durationMs: Date.now() - startTime,
        attempt,
      });
      throw lastError;
    }
  }

  throw lastError ?? new Error("AETHER-ZENITH_ERR: Unexpected retry loop exit without a specific error.");
}

